import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: String {
        switch self {
        case .development:
            return "https://dev.api.example.com"
        case .staging:
            return "https://staging.api.example.com"
        case .production:
            return "https://api.example.com"
        }
    }
}

enum NetworkError: Error, CustomStringConvertible {
    case invalidURL
    case requestFailed
    case decodingFailed
    
    var description: String {
        switch self {
        case .invalidURL:
            return "Invalid URL."
        case .requestFailed:
            return "Request failed."
        case .decodingFailed:
            return "Decoding failed."
        }
    }
}

class NetworkManager {
    private let session = URLSession.shared
    private var environment: Environment
    
    init(environment: Environment) {
        self.environment = environment
    }
    
    func fetchUserData(completion: @escaping (Result<User, NetworkError>) -> Void) {
        guard let url = URL(string: "\(environment.baseURL)/user") else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                print("Error: \(error)")
                completion(.failure(.requestFailed))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode), let data = data else {
                completion(.failure(.requestFailed))
                return
            }
            
            do {
                let user = try JSONDecoder().decode(User.self, from: data)
                completion(.success(user))
            } catch {
                print("Error decoding: \(error)")
                completion(.failure(.decodingFailed))
            }
        }.resume()
    }
    
    func authenticateUser(username: String, password: String, completion: @escaping (Result<AuthToken, NetworkError>) -> Void) {
        guard let url = URL(string: "\(environment.baseURL)/auth") else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let authData = ["username": username, "password": password]
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: authData, options: [])
        } catch {
            print("Error encoding authentication data: \(error)")
            completion(.failure(.requestFailed))
            return
        }
        
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                print("Error: \(error)")
                completion(.failure(.requestFailed))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode), let data = data else {
                completion(.failure(.requestFailed))
                return
            }
            
            do {
                let authToken = try JSONDecoder().decode(AuthToken.self, from: data)
                completion(.success(authToken))
            } catch {
                print("Error decoding auth token: \(error)")
                completion(.failure(.decodingFailed))
            }
        }.resume()
    }
}

struct User: Codable {
    let id: Int
    let name: String
    let email: String
}

struct AuthToken: Codable {
    let token: String
}